mapper.select:
SELECT * FROM t_diet
WHERE user_id = #{userId}
  AND deleted = 0
  AND meal_type = #{mealType}
  AND occurred_at >= #{from}
  AND occurred_at <= #{to}
ORDER BY occurred_at DESC, id DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM t_diet
WHERE user_id = #{userId}
  AND deleted = 0
  AND meal_type = #{mealType}
  AND occurred_at >= #{from}
  AND occurred_at <= #{to}

SELECT
  COALESCE(SUM(kcal), 0)        AS kcal,
  COALESCE(SUM(protein_g), 0)   AS proteinG,
  COALESCE(SUM(carb_g), 0)      AS carbG,
  COALESCE(SUM(fat_g), 0)       AS fatG
FROM t_diet
WHERE user_id = #{userId}
  AND deleted = 0
  AND occurred_at >= #{from}
  AND occurred_at <= #{to}
